const body = $input.first().json.body;

if (!body.amount || isNaN(Number(body.amount)) || Number(body.amount) <= 0) {
  throw new Error('amount es requerido y debe ser un número positivo');
}

return [{
  json: {
    amount: Number(body.amount),
    description: body.description || null,
    category_id: body.category_id ? Number(body.category_id) : null,
    user_id: body.user_id ? Number(body.user_id) : 1,
    expense_date: body.expense_date || new Date().toISOString().split('T')[0],
    capture_channel: body.capture_channel || 'pwa',
    payment_method: body.payment_method || null,
    status: 'confirmed'
  }
}];
